def pre(i):
    if not isinstance(i, tuple) or len(i) != 2:
        return False
    lst, target = i
    if not isinstance(lst, list):
        return False
    if not isinstance(target, int):
        return False
    # all elements must be integers
    for x in lst:
        if not isinstance(x, int):
            return False
    # list must be sorted in non‑decreasing order
    for a, b in zip(lst, lst[1:]):
        if a > b:
            return False
    return True


def post(i, o):
    if not pre(i):
        return False
    lst, target = i
    if not isinstance(o, int):
        return False
    if target in lst:
        return 0 <= o < len(lst) and lst[o] == target
    else:
        return o == -1
